// Generated by OrchestKit Claude Plugin
// Created: 2026-04-22

/**
 * Context-Crossing Warn — Issue #1470
 *
 * One-shot active alert when cumulative session context crosses a token
 * threshold (default 150k). Hosted on PostToolUse so it catches the actual
 * pain point: "a subagent/tool just returned a large output and now context
 * has quietly ballooned over 150k without me noticing."
 *
 * Tracks an estimate of tokens added per tool call in a per-session state
 * file. On first crossing, injects a one-shot `additionalContext` message
 * suggesting `/clear` (new task) or `/compact` (keep history). Subsequent
 * tool calls are silent. State is keyed by session id — a fresh session
 * auto-re-arms because the state file does not exist yet.
 *
 * Config:
 *   ORK_NO_CTX_WARN=1          — fully disable
 *   ORK_CTX_WARN_THRESHOLD=N   — override threshold (default 150000)
 *
 * Complements `claude-hud` (passive statusline) — claude-hud shows
 * percentage passively; this hook interrupts at threshold crossing.
 */

import { existsSync, readFileSync, mkdirSync, appendFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import {
  outputSilentSuccess,
  outputWithContext,
  getProjectDir,
  getSessionId,
} from '../lib/common.js';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { NOOP_CTX } from '../lib/context.js';
import {
  estimateTokens,
  detectContentKind,
  extractToolOutputText,
  type ContentKind,
} from '../lib/token-estimator.js';

const HOOK_NAME = 'posttool/context-crossing-warn';
const DEFAULT_THRESHOLD = 150_000;

interface AccumState {
  estimatedTokens: number;
  crossings: Record<string, boolean>;
  updatedAt: string;
  lastToolName?: string;
  /** Counts of observed content kinds — useful for debugging estimator accuracy (#1478). */
  kindCounts?: Partial<Record<ContentKind, number>>;
  /** Number of image responses seen (not counted toward tokens — tokenized separately by the model). */
  imageResponses?: number;
}

function getStateFile(projectDir: string, sessionId: string): string {
  return join(
    projectDir,
    '.claude',
    'state',
    `session-${sessionId}-token-accum.json`,
  );
}

function loadState(path: string): AccumState {
  if (existsSync(path)) {
    try {
      const parsed = JSON.parse(readFileSync(path, 'utf8')) as Partial<AccumState>;
      return {
        estimatedTokens: Number(parsed.estimatedTokens) || 0,
        crossings: parsed.crossings && typeof parsed.crossings === 'object' ? parsed.crossings : {},
        updatedAt: parsed.updatedAt || new Date().toISOString(),
        lastToolName: parsed.lastToolName,
        kindCounts: parsed.kindCounts && typeof parsed.kindCounts === 'object' ? parsed.kindCounts : {},
        imageResponses: Number(parsed.imageResponses) || 0,
      };
    } catch {
      // corrupt — start fresh
    }
  }
  return {
    estimatedTokens: 0,
    crossings: {},
    updatedAt: new Date().toISOString(),
    kindCounts: {},
    imageResponses: 0,
  };
}

interface EstimateResult {
  tokens: number;
  kind: ContentKind;
}

function estimateAddedTokens(input: HookInput): EstimateResult {
  const text = extractToolOutputText(input);
  if (!text) return { tokens: 0, kind: 'unknown' };
  const kind = detectContentKind(input.tool_name, text);
  const tokens = estimateTokens(text, kind);
  return { tokens, kind };
}

function logImageEvent(projectDir: string, toolName: string | undefined, charLen: number): void {
  try {
    const logPath = join(projectDir, '.claude', 'telemetry', 'image-responses.jsonl');
    mkdirSync(dirname(logPath), { recursive: true });
    appendFileSync(
      logPath,
      JSON.stringify({
        timestamp: new Date().toISOString(),
        tool: toolName ?? 'unknown',
        char_len: charLen,
      }) + '\n',
    );
  } catch {
    // telemetry is best-effort
  }
}

function getThreshold(): number {
  const raw = process.env.ORK_CTX_WARN_THRESHOLD;
  if (!raw) return DEFAULT_THRESHOLD;
  const parsed = parseInt(raw, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) return DEFAULT_THRESHOLD;
  return parsed;
}

function formatNumber(n: number): string {
  return n.toLocaleString('en-US');
}

export function contextCrossingWarn(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  if (process.env.ORK_NO_CTX_WARN === '1') {
    return outputSilentSuccess();
  }

  try {
    const projectDir = ctx.projectDir || getProjectDir();
    const sessionId = ctx.sessionId || getSessionId();
    const statePath = getStateFile(projectDir, sessionId);
    const state = loadState(statePath);
    const threshold = getThreshold();

    const { tokens: added, kind } = estimateAddedTokens(input);
    state.estimatedTokens += added;
    state.updatedAt = new Date().toISOString();
    if (input.tool_name) state.lastToolName = input.tool_name;

    // Track content-kind distribution for estimator-accuracy debugging.
    state.kindCounts = state.kindCounts ?? {};
    state.kindCounts[kind] = (state.kindCounts[kind] ?? 0) + 1;

    // Image responses are tokenized at rates we can't derive from char length
    // (model-side vision tokenization is separate). Log them for visibility so
    // that "total tokens" estimates can be corrected downstream if needed.
    if (kind === 'image') {
      state.imageResponses = (state.imageResponses ?? 0) + 1;
      const sampleText = extractToolOutputText(input);
      logImageEvent(projectDir, input.tool_name, sampleText.length);
    }

    const key = String(threshold);
    const alreadyCrossed = state.crossings?.[key] === true;
    const shouldFire = !alreadyCrossed && state.estimatedTokens >= threshold;

    if (shouldFire) {
      state.crossings = { ...(state.crossings ?? {}), [key]: true };
    }

    try {
      mkdirSync(join(projectDir, '.claude', 'state'), { recursive: true });
      atomicWriteSync(statePath, JSON.stringify(state, null, 2));
    } catch {
      // non-fatal — state file is best-effort
    }

    if (shouldFire) {
      const msg =
        `[context] Session context crossed ~${formatNumber(threshold)} tokens ` +
        `(est. ${formatNumber(state.estimatedTokens)}). ` +
        `/clear to start a fresh task with zero context cost, ` +
        `/compact to keep history and continue.`;
      ctx.log(
        HOOK_NAME,
        `crossing fired at ${state.estimatedTokens} tokens (threshold ${threshold})`,
      );
      return outputWithContext(msg);
    }

    return outputSilentSuccess();
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    ctx.log(HOOK_NAME, `failed: ${msg}`, 'warn');
    return outputSilentSuccess();
  }
}

export default contextCrossingWarn;
